import { create } from 'zustand';
import { persist } from 'zustand/middleware';

const useCartStore = create(
  persist(
    (set, get) => ({
      items: [],
      addItem: (product) => set((state) => {
        const existing = state.items.find(item => item.id === product.id);
        if (existing) {
          return { items: state.items.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item) };
        }
        return { items: [...state.items, { ...product, quantity: 1 }] };
      }),
      removeItem: (id) => set((state) => ({ items: state.items.filter(item => item.id !== id) })),
      updateQuantity: (id, quantity) => set((state) => ({
        items: quantity <= 0 ? state.items.filter(item => item.id !== id) : state.items.map(item => item.id === id ? { ...item, quantity } : item)
      })),
      getTotal: () => get().items.reduce((sum, item) => sum + (item.prix * item.quantity), 0),
      clearCart: () => set({ items: [] })
    }),
    { name: 'cart-storage' }
  )
);
export default useCartStore;
```

