const getFilteredProducts = (products, filters) => {
  let result = [...products];
  // Filtre catégories
  if (filters.categories.length) {
    result = result.filter(p => filters.categories.includes(p.category));
  }
  // Filtre prix
  result = result.filter(p => p.price >= filters.priceRange.min && p.price <= filters.priceRange.max);
  // Filtre marques
  if (filters.brands.length) {
    result = result.filter(p => filters.brands.includes(p.brand));
  }
  // Tri
  if (filters.sortBy === 'prix_asc') result.sort((a,b) => a.price - b.price);
  else if (filters.sortBy === 'prix_desc') result.sort((a,b) => b.price - a.price);
  else if (filters.sortBy === 'popularite') result.sort((a,b) => b.rating - a.rating);
  return result;
};
