const usePaginationStore = create((set, get) => ({
  currentPage: 1,
  itemsPerPage: 12,
  setPage: (page) => set({ currentPage: page }),
  nextPage: (totalItems) => {
    const { currentPage, itemsPerPage } = get();
    const maxPage = Math.ceil(totalItems / itemsPerPage);
    if (currentPage < maxPage) set({ currentPage: currentPage + 1 });
  },
  prevPage: () => {
    const { currentPage } = get();
    if (currentPage > 1) set({ currentPage: currentPage - 1 });
  },
  goToPage: (page, totalItems) => {
    const maxPage = Math.ceil(totalItems / get().itemsPerPage);
    if (page >= 1 && page <= maxPage) set({ currentPage: page });
  },
  totalPages: (totalItems) => Math.ceil(totalItems / get().itemsPerPage)
}));
```

